import { useState, useEffect } from "react";
import authStore from "./stores/auth-store";
import 'react-toastify/dist/ReactToastify.css';


function App() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    // Initialize auth khi app khởi động
    authStore.getState().initialize();
  }, []);

  return (
    <>
      <Header />
      <Outlet />
      <Footer />
      <ToastContainer
        position="top-right"
        autoClose={3000}
        hideProgressBar={false}
        newestOnTop={false}
        closeOnClick
        rtl={false}
        pauseOnFocusLoss
        draggable
        pauseOnHover
        theme="light"
      />
    </>
  );
}

export default App;

import 'react-image-crop/dist/ReactCrop.css';
import '../../styles/components/profile/crop-modal.css';

const CropModal = ({
    showCropModal,
    selectedImage,
    crop,
    setCrop,
    completedCrop,
    setCompletedCrop,
    imageRef,
    previewUrl,
    uploadError,
    setUploadError,
    handleCancelCrop,
    handleCropAndUpload,
    uploadingAvatar
}) => {
    if (!showCropModal) return null;

    return (
        <div className="pf-crop-modal-overlay">
            <div className="pf-crop-modal">
                <div className="pf-crop-modal-header">
                    <h3>Cắt ảnh đại diện</h3>
                    <button
                        className="pf-crop-modal-close"
                        onClick={handleCancelCrop}
                    >
                        <FiX />
                    </button>
                </div>
                <div className="pf-crop-modal-body">
                    {uploadError && (
                        <div className="pf-crop-error">
                            <span>{uploadError}</span>
                            <button
                                className="pf-crop-error-close"
                                onClick={() => setUploadError('')}
                            >
                                <FiX />
                            </button>
                        </div>
                    )}
                    <div className="pf-crop-body-content">
                        <div className="pf-crop-container">
                            <ReactCrop
                                src={selectedImage}
                                crop={crop}
                                onChange={(newCrop) => {
                                    setCrop(newCrop);
                                }}
                                onComplete={(c) => {
                                    setCompletedCrop(c);
                                }}
                                aspect={1}
                                circularCrop
                            >
                                <img
                                    ref={(ref) => {
                                        imageRef.current = ref;
                                    }}
                                    src={selectedImage}
                                    alt="Crop preview"
                                    className="pf-crop-image"
                                    onLoad={(e) => {
                                        imageRef.current = e.target;
                                    }}
                                    onError={(e) => {
                                        setUploadError('Không thể tải ảnh để crop');
                                    }}
                                />
                            </ReactCrop>
                        </div>
                        <div className="pf-crop-preview">
                            <h4>Xem trước</h4>
                            {previewUrl ? (
                                <div className="pf-crop-preview-circle">
                                    <img
                                        src={previewUrl}
                                        alt="Preview"
                                        className="pf-crop-preview-img"
                                    />
                                </div>
                            ) : completedCrop ? (
                                <div className="pf-crop-preview-circle">
                                    <div className="pf-crop-preview-loading">
                                        <FiLoader className="pf-spin" />
                                    </div>
                                </div>
                            ) : (
                                <div className="pf-crop-preview-circle">
                                    <p className="pf-crop-preview-placeholder">Hãy chọn vùng cắt</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
                <div className="pf-crop-modal-footer">
                    <button
                        className="pf-crop-cancel-btn"
                        onClick={handleCancelCrop}
                    >
                        Hủy
                    </button>
                    <button
                        className="pf-crop-save-btn"
                        onClick={handleCropAndUpload}
                        disabled={!completedCrop || uploadingAvatar}
                    >
                        {uploadingAvatar ? <FiLoader className="pf-spin" /> : <FiSave />}
                        {uploadingAvatar ? 'Đang tải...' : 'Lưu ảnh'}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CropModal;

import '../../styles/components/profile/edit-actions.css';

const EditActions = ({
    isEditing,
    isChangingPassword,
    updateLoading,
    handleUpdateProfile,
    handleOpenPasswordModal,
    setIsEditing,
    setIsChangingPassword,
    setFormErrors
}) => {
    return (
        <div className="pf-edit-actions">

            {/* Chỉ hiển thị nút Lưu và Hủy khi đang edit profile */}
            {isEditing && (
                <>
                    <button
                        className="pf-save-btn"
                        onClick={handleUpdateProfile}
                        disabled={updateLoading}
                    >
                        {updateLoading ? <FiLoader className="pf-spin" /> : <FiSave />} Lưu
                    </button>
                    <button
                        className="pf-cancel-btn"
                        onClick={() => {
                            setIsEditing(false);
                            setIsChangingPassword(false);
                            setFormErrors({});
                        }}
                        disabled={updateLoading}
                    >
                        <FiX /> Hủy
                    </button>
                </>
            )}
        </div>
    );
};

export default EditActions;

import '../../styles/components/profile/password-change-form.css';

const PasswordChangeForm = ({
    isChangingPassword,
    passwordData,
    formErrors,
    updateLoading,
    handlePasswordChange
}) => {
    if (!isChangingPassword) return null;

    return (
        <div className="pf-password-section">
            <h3>Đổi mật khẩu</h3>
            <div className="pf-password-grid">
                <div className="pf-info-card">
                    <label className="pf-info-label">Mật khẩu hiện tại</label>
                    <input
                        type="password"
                        name="currentPassword"
                        className={`pf-info-input ${formErrors.currentPassword ? 'pf-input-error' : ''}`}
                        value={passwordData.currentPassword}
                        onChange={handlePasswordChange}
                        placeholder="Nhập mật khẩu hiện tại"
                    />
                    {formErrors.currentPassword && <span className="pf-error-text">{formErrors.currentPassword}</span>}
                </div>

                <div className="pf-info-card">
                    <label className="pf-info-label">Mật khẩu mới</label>
                    <input
                        type="password"
                        name="newPassword"
                        className={`pf-info-input ${formErrors.newPassword ? 'pf-input-error' : ''}`}
                        value={passwordData.newPassword}
                        onChange={handlePasswordChange}
                        placeholder="Nhập mật khẩu mới"
                    />
                    {formErrors.newPassword && <span className="pf-error-text">{formErrors.newPassword}</span>}
                </div>

                <div className="pf-info-card">
                    <label className="pf-info-label">Xác nhận mật khẩu</label>
                    <input
                        type="password"
                        name="confirmPassword"
                        className={`pf-info-input ${formErrors.confirmPassword ? 'pf-input-error' : ''}`}
                        value={passwordData.confirmPassword}
                        onChange={handlePasswordChange}
                        placeholder="Nhập lại mật khẩu mới"
                    />
                    {formErrors.confirmPassword && <span className="pf-error-text">{formErrors.confirmPassword}</span>}
                </div>
            </div>
        </div>
    );
};

export default PasswordChangeForm;

import { formatDate, getAvatarUrl } from '../../utils/profile-utils';
import '../../styles/components/profile/profile-header.css';

const ProfileHeader = ({
    profileData,
    isOwnProfile,
    avatarUrl,
    avatarLoading,
    isEditing,
    isChangingPassword,
    setIsEditing,
    setIsChangingPassword,
    handleFileSelect,
    uploadingAvatar,
    setUser,
    handleOpenPasswordModal
}) => {
    return (
        <div className="pf-profile-header">
            <div className="pf-avatar-section">
                {avatarLoading ? (
                    <div className="pf-avatar-loading">
                        <FiLoader className="pf-spin" />
                    </div>
                ) : avatarUrl ? (
                    <img
                        src={avatarUrl}
                        alt={`${profileData.username}'s avatar`}
                        className="pf-avatar-image"
                        onError={(e) => {
                        }}
                    />
                ) : profileData.avatarURL ? (
                    <img
                        src={getAvatarUrl(profileData.avatarURL)}
                        alt={`${profileData.username}'s avatar`}
                        className="pf-avatar-image"
                        onError={(e) => {
                        }}
                    />
                ) : null}
                <div
                    className="pf-avatar-fallback"
                    style={{
                        display: (avatarUrl || profileData.avatarURL) && !avatarLoading ? 'none' : 'flex'
                    }}
                >
                    {profileData.username?.charAt(0).toUpperCase() || 'U'}
                </div>

                {/* Avatar Upload Button */}
                {isOwnProfile && (
                    <div className="pf-avatar-upload">
                        <input
                            type="file"
                            id="avatar-upload"
                            accept="image/png,image/jpeg,image/jpg"
                            onChange={(e) => handleFileSelect(e, setUser)}
                            style={{ display: 'none' }}
                            disabled={uploadingAvatar}
                        />
                        <label htmlFor="avatar-upload" className="pf-avatar-upload-btn">
                            {uploadingAvatar ? (
                                <FiLoader className="pf-spin" />
                            ) : (
                                <FiCamera />
                            )}
                        </label>
                    </div>
                )}
            </div>
            <div className="pf-user-info">
                <h1 className="pf-username">{profileData.username || 'Unknown User'}</h1>
                <p className="pf-fullname">{profileData.fullName || 'Chưa cập nhật'}</p>
                <div className="pf-user-meta">
                    <span className="pf-join-date">
                        <FiCalendar className="pf-meta-icon" />
                        Tham gia: {formatDate(profileData.createdAt)}
                    </span>
                </div>
            </div>
            {isOwnProfile && (
                <div className="pf-actions">
                    {!isEditing && !isChangingPassword && (
                        <>
                            <button className="pf-edit-btn" onClick={() => setIsEditing(true)}>
                                <FiEdit className="pf-btn-icon" /> Cập nhật thông tin
                            </button>
                            <button className="pf-edit-btn" onClick={handleOpenPasswordModal}>
                                <FiLock className="pf-btn-icon" /> Đổi mật khẩu
                            </button>
                        </>
                    )}
                </div>
            )}
        </div>
    );
};

export default ProfileHeader;

import '../../styles/components/profile/profile-stats.css';
import '../../styles/components/profile/profile-stats-loading.css';
import { useStats } from '../../hooks/use-stats';
import { formatScore, formatRank, formatTime } from '../../utils/stats-utils';

const ProfileStats = ({ profileData }) => {
    const { stats, loading: statsLoading, error: statsError } = useStats('profile');
    
    const displayStats = stats || {};

    return (
        <>
            {/* Main Stats Section */}
            <div className="pf-stats-section">
                <h2 className="pf-section-title">
                    <FiTarget className="pf-section-icon" />
                    Thống kê & Thành tích
                </h2>

                {statsLoading ? (
                    <div className="pf-stats-loading">Đang tải thống kê...</div>
                ) : statsError ? (
                    <div className="pf-stats-error">
                        <p>Lỗi: {statsError}</p>
                    </div>
                ) : (
                    <>
                        {/* Stats Grid */}
                        <div className="pf-stats-grid">
                            <div className="pf-stat-card pf-stat-primary">
                                <FiAward className="pf-stat-icon" />
                                <div className="pf-stat-value">{formatScore(displayStats.highestScore)}</div>
                                <div className="pf-stat-label">Điểm cao nhất</div>
                            </div>
                            <div className="pf-stat-card pf-stat-secondary">
                                <FiUsers className="pf-stat-icon" />
                                <div className="pf-stat-value">{formatRank(displayStats.highestRank)}</div>
                                <div className="pf-stat-label">Xếp hạng cao nhất</div>
                            </div>
                            <div className="pf-stat-card pf-stat-accent">
                                <FiClock className="pf-stat-icon" />
                                <div className="pf-stat-value">{formatTime(displayStats.fastestTime)}</div>
                                <div className="pf-stat-label">Thời gian nhanh nhất</div>
                            </div>
                            <div className="pf-stat-card pf-stat-info">
                                <FaRunning className="pf-stat-icon" />
                                <div className="pf-stat-value">{displayStats.bestTopic || 'N/A'}</div>
                                <div className="pf-stat-label">Chủ đề tốt nhất</div>
                            </div>
                        </div>
                    </>
                )}


            </div>
        </>
    );
};

export default ProfileStats;

import { useEffect } from 'react';
import '../../styles/components/room/answer-result-popup.css';

/**
 * AnswerResultPopup - Hiển thị kết quả trả lời câu hỏi với animation đẹp mắt
 */
const AnswerResultPopup = ({ result, onClose }) => {
    useEffect(() => {
        // Tự động đóng sau 3 giây nếu không có props onClose
        if (!onClose) return;

        const timer = setTimeout(() => {
            onClose();
        }, 3000);

        return () => clearTimeout(timer);
    }, [onClose]);

    if (!result) return null;

    const { isCorrect, score, streak, streakMultiplier } = result;

    // Lấy icon và message dựa trên kết quả
    const getResultInfo = () => {
        if (isCorrect) {
            return {
                icon: <FaCheckCircle />,
                title: 'Đúng rồi!',
                bgColor: '#4CAF50',
                animation: 'popup-bounce-in'
            };
        } else {
            return {
                icon: <FaTimesCircle />,
                title: 'Sai rồi!',
                bgColor: '#f44336',
                animation: 'popup-shake'
            };
        }
    };

    // Lấy streak badge
    const getStreakBadge = () => {
        if (!isCorrect || !streak || streak < 3) return null;

        if (streak >= 10) {
            return {
                text: <><IoFlame /><IoFlame /><IoFlame /> UNSTOPPABLE!</>,
                color: '#FF1744',
                label: 'x2.0 Bonus'
            };
        } else if (streak >= 5) {
            return {
                text: <><IoFlame /><IoFlame /> ON FIRE!</>,
                color: '#FF6F00',
                label: 'x1.5 Bonus'
            };
        } else if (streak >= 3) {
            return {
                text: <><IoFlame /> FIRE STREAK!</>,
                color: '#FFC400',
                label: 'x1.2 Bonus'
            };
        }
        return null;
    };

    const resultInfo = getResultInfo();
    const streakBadge = getStreakBadge();

    return (
        <div className="answer-result-overlay">
            <div
                className={`answer-result-popup ${resultInfo.animation}`}
                style={{ backgroundColor: resultInfo.bgColor }}
            >
                <div className="popup-icon">{resultInfo.icon}</div>
                <h2 className="popup-title">{resultInfo.title}</h2>

                {isCorrect && (
                    <div className="popup-score">
                        <div className="score-value">+{score}</div>
                        <div className="score-label">điểm</div>
                    </div>
                )}

                {streakBadge && (
                    <div className="popup-streak" style={{ backgroundColor: `${streakBadge.color}33` }}>
                        <div className="streak-text" style={{ color: streakBadge.color }}>
                            {streakBadge.text}
                        </div>
                        <div className="streak-label">{streakBadge.label}</div>
                        <div className="streak-count">Streak: {streak}</div>
                    </div>
                )}

                {!isCorrect && (
                    <div className="popup-message">
                        Đừng lo! Cố gắng ở câu tiếp theo nhé! <GiMuscleUp />
                    </div>
                )}

                <button className="popup-close-btn" onClick={onClose}>
                    <FaTimes />
                </button>
            </div>
        </div>
    );
};

export default AnswerResultPopup;

import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import useGameStore from '../../stores/use-game-store';
import '../../styles/components/room/game-play.css';

/**
 * GamePlay Component - Real-time quiz gameplay
 * Similar to Kahoot/Quizizz game interface
 */
const GamePlay = ({ isHost, onLeave }) => {
    const { roomId } = useParams();

    const {
        currentQuestion,
        currentQuestionIndex,
        totalQuestions,
        timeRemaining,
        selectedAnswer,
        hasAnswered,
        answerResult,
        players,
        submitAnswer,
        nextQuestion
    } = useGameStore();

    const [showResults, setShowResults] = useState(false);

    useEffect(() => {
        // Show results for 3 seconds after answering
        if (hasAnswered && answerResult) {
            setShowResults(true);
            const timer = setTimeout(() => {
                setShowResults(false);
            }, 3000);
            return () => clearTimeout(timer);
        }
    }, [hasAnswered, answerResult]);

    /**
     * Handle answer selection
     */
    const handleAnswerClick = (answerId) => {
        if (hasAnswered) return;
        submitAnswer(answerId);
    };

    /**
     * Handle next question (host only)
     */
    const handleNextQuestion = () => {
        if (isHost) {
            nextQuestion();
        }
    };

    if (!currentQuestion) {
        return (
            <div className="game-play-container">
                <div className="loading-question">
                    <div className="spinner"></div>
                    <p>Đang tải câu hỏi...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="game-play-container">
            {/* Header */}
            <div className="game-header">
                <div className="question-progress">
                    <span>Câu {currentQuestionIndex}/{totalQuestions}</span>
                </div>
                <div className="timer-display">
                    <span className={timeRemaining <= 5 ? 'timer-critical' : ''}>
                        ⏱️ {timeRemaining}s
                    </span>
                </div>
                <button className="btn-leave" onClick={onLeave}>
                    Rời phòng
                </button>
            </div>

            {/* Question Display */}
            <div className="question-section">
                <h2 className="question-text">{currentQuestion.questionText}</h2>

                {currentQuestion.imageUrl && (
                    <img
                        src={currentQuestion.imageUrl}
                        alt="Question"
                        className="question-image"
                    />
                )}
            </div>

            {/* Answer Options */}
            {!showResults ? (
                <div className="answers-grid">
                    {currentQuestion.answers?.map((answer, index) => (
                        <button
                            key={answer.id}
                            className={`answer-option ${selectedAnswer === answer.id ? 'selected' : ''
                            } ${hasAnswered ? 'disabled' : ''}`}
                            onClick={() => handleAnswerClick(answer.id)}
                            disabled={hasAnswered}
                            style={{
                                animationDelay: `${index * 0.1}s`,
                                backgroundColor: getAnswerColor(index)
                            }}
                        >
                            <span className="answer-icon">{getAnswerIcon(index)}</span>
                            <span className="answer-text">{answer.answerText}</span>
                        </button>
                    ))}
                </div>
            ) : (
                <div className="answer-result-section">
                    <div className={`result-card ${answerResult?.isCorrect ? 'correct' : 'incorrect'}`}>
                        <div className="result-icon">
                            {answerResult?.isCorrect ? '✅' : '❌'}
                        </div>
                        <h3>
                            {answerResult?.isCorrect ? 'Chính xác!' : 'Sai rồi!'}
                        </h3>
                        <p className="points-earned">
                            +{answerResult?.score || 0} điểm
                        </p>

                        {/* Show correct answer if wrong */}
                        {!answerResult?.isCorrect && (
                            <div className="correct-answer-display">
                                <p>Đáp án đúng:</p>
                                <p className="correct-answer-text">
                                    {currentQuestion.answers?.find(a => a.isCorrect)?.answerText}
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Players who answered */}
                    <div className="players-answered">
                        <h4>Đã trả lời: {players.filter(p => p.hasAnswered).length}/{players.length}</h4>
                    </div>

                    {/* Next button for host */}
                    {isHost && (
                        <button
                            className="btn-next-question"
                            onClick={handleNextQuestion}
                        >
                            Câu tiếp theo →
                        </button>
                    )}
                </div>
            )}

            {/* Mini Leaderboard */}
            <div className="mini-leaderboard">
                <h4>🏆 Top 3</h4>
                <div className="top-players">
                    {players.slice(0, 3).map((player, index) => (
                        <div key={player.userId} className="top-player">
                            <span className="rank">#{index + 1}</span>
                            <span className="name">{player.username}</span>
                            <span className="score">{player.totalScore || 0}</span>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

/**
 * Get color for answer option
 */
const getAnswerColor = (index) => {
    const colors = ['#e74c3c', '#3498db', '#f39c12', '#2ecc71'];
    return colors[index % colors.length];
};

/**
 * Get icon for answer option
 */
const getAnswerIcon = (index) => {
    const icons = ['△', '◇', '○', '□'];
    return icons[index % icons.length];
};

export default GamePlay;

import { useNavigate } from 'react-router-dom';
import useGameStore from '../../stores/use-game-store';
import '../../styles/components/room/game-results.css';

/**
 * GameResults Component - Final leaderboard and statistics
 * Similar to Kahoot/Quizizz results screen
 */
const GameResults = ({ onExit, gameResults }) => {
    const navigate = useNavigate();

    const {
        leaderboard: storeLeaderboard,
        totalQuestions,
        players
    } = useGameStore();

    const leaderboard = gameResults?.ranking || storeLeaderboard;
    const totalQs = gameResults?.totalQuestions || totalQuestions;

    /**
     * Handle play again
     */
    const handlePlayAgain = () => {
        // Navigate back to dashboard to create/join new game
        navigate('/dashboard');
    };

    /**
     * Get medal emoji for ranking
     */
    const getMedal = (rank) => {
        switch (rank) {
            case 1: return '🥇';
            case 2: return '🥈';
            case 3: return '🥉';
            default: return '🏅';
        }
    };

    /**
     * Get podium position class
     */
    const getPodiumClass = (rank) => {
        switch (rank) {
            case 1: return 'podium-first';
            case 2: return 'podium-second';
            case 3: return 'podium-third';
            default: return '';
        }
    };

    /**
     * Calculate player accuracy percentage
     */
    const calculateAccuracy = (player) => {
        if (!player.correctAnswers && !player.totalAnswers) return 0;
        const correct = player.correctAnswers || 0;
        const total = player.totalAnswers || totalQs || 0;
        if (total === 0) return 0;
        return Math.round((correct / total) * 100);
    };

    return (
        <div className="game-results-container">
            {/* Confetti animation */}
            <div className="confetti-container">
                {[...Array(50)].map((_, i) => (
                    <div key={i} className="confetti" style={{
                        left: `${Math.random() * 100}%`,
                        animationDelay: `${Math.random() * 3}s`,
                        backgroundColor: ['#e74c3c', '#3498db', '#f39c12', '#2ecc71'][Math.floor(Math.random() * 4)]
                    }} />
                ))}
            </div>

            {/* Header */}
            <div className="results-header">
                <h1><MdCelebration size={40} color="#FFD700" style={{verticalAlign: 'middle'}} /> Trò chơi kết thúc!</h1>
                <p className="game-stats">
                    Tổng số câu: {totalQs} | Người chơi: {leaderboard.length}
                </p>
            </div>

            {/* Podium - Top 3 */}
            <div className="podium-section">
                <h2>🏆 Podium</h2>
                <div className="podium">
                    {leaderboard.slice(0, 3).map((player, index) => {
                        const podiumOrder = index === 0 ? 0 : index === 1 ? 2 : 1; // Center winner
                        const rank = player.rank || (index + 1);
                        return (
                            <div
                                key={player.userId}
                                className={`podium-place ${getPodiumClass(rank)}`}
                                style={{ order: podiumOrder }}
                            >
                                <div className="player-avatar">
                                    <img
                                        src={player.avatar || '/default-avatar.png'}
                                        alt={player.userName || 'Player'}
                                        onError={(e) => {
                                            e.target.src = '/default-avatar.png';
                                        }}
                                    />
                                </div>
                                <div className="medal">{getMedal(rank)}</div>
                                <h3>{player.userName || `User${player.userId}`}</h3>
                                <p className="score">{player.totalScore || 0} điểm</p>
                                <div className={`podium-base rank-${rank}`}>
                                    <span className="rank-number">#{rank}</span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Full Leaderboard */}
            <div className="leaderboard-section">
                <h2>📊 Bảng xếp hạng</h2>
                <div className="leaderboard-table">
                    <div className="leaderboard-header">
                        <span>Hạng</span>
                        <span>Tên</span>
                        <span>Điểm</span>
                        <span>Độ chính xác</span>
                    </div>
                    <div className="leaderboard-body">
                        {leaderboard.map((player, index) => {
                            const rank = player.rank || (index + 1);
                            return (
                                <div
                                    key={player.userId}
                                    className={`leaderboard-row ${rank <= 3 ? 'top-three' : ''}`}
                                >
                                    <span className="rank">
                                        {rank <= 3 ? getMedal(rank) : `#${rank}`}
                                    </span>
                                    <span className="player-name">
                                        <img
                                            src={player.avatar || '/default-avatar.png'}
                                            alt={player.userName || 'Player'}
                                            className="mini-avatar"
                                            onError={(e) => {
                                                e.target.src = '/default-avatar.png';
                                            }}
                                        />
                                        {player.userName || `User${player.userId}`}
                                    </span>
                                    <span className="score">{player.totalScore || 0}</span>
                                    <span className="accuracy">
                                        {calculateAccuracy(player)}%
                                    </span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Action buttons */}
            <div className="results-actions">
                <button className="btn-primary" onClick={handlePlayAgain}>
                    Chơi lại
                </button>
                <button className="btn-secondary" onClick={onExit}>
                    Về trang chủ
                </button>
            </div>
        </div>
    );
};

export default GameResults;

import { useEffect, useState } from 'react';
import useRoomStore from '../../stores/use-room-store';
import '../../styles/components/room/player-list.css';

const PlayerList = ({ roomId, isHost }) => {
    const { roomPlayers, currentRoom } = useRoomStore();
    const [animatingPlayers, setAnimatingPlayers] = useState(new Set());
    const [playerStates, setPlayerStates] = useState(new Map());

    // Track player changes for animations
    useEffect(() => {
        const currentPlayerIds = new Set(roomPlayers.map(p => p.id));
        const previousPlayerIds = new Set(Array.from(playerStates.keys()));

        // Find newly joined players
        const newPlayers = roomPlayers.filter(p => !previousPlayerIds.has(p.id));
        // Find players who left
        const leftPlayerIds = Array.from(previousPlayerIds).filter(id => !currentPlayerIds.has(id));

        // Animate new players
        newPlayers.forEach(player => {
            setAnimatingPlayers(prev => new Set(prev).add(`join-${player.id}`));
            setTimeout(() => {
                setAnimatingPlayers(prev => {
                    const newSet = new Set(prev);
                    newSet.delete(`join-${player.id}`);
                    return newSet;
                });
            }, 600);
        });

        // Animate leaving players (remove from DOM after animation)
        leftPlayerIds.forEach(playerId => {
            setAnimatingPlayers(prev => new Set(prev).add(`leave-${playerId}`));
            setTimeout(() => {
                setPlayerStates(prev => {
                    const newMap = new Map(prev);
                    newMap.delete(playerId);
                    return newMap;
                });
                setAnimatingPlayers(prev => {
                    const newSet = new Set(prev);
                    newSet.delete(`leave-${playerId}`);
                    return newSet;
                });
            }, 400);
        });

        // Update player states
        const newStates = new Map();
        roomPlayers.forEach(player => {
            newStates.set(player.id, player);
        });
        setPlayerStates(newStates);

    }, [roomPlayers]);

    const isPlayerHost = (playerId) => {
        return currentRoom?.hostId === playerId || currentRoom?.ownerId === playerId;
    };

    const getPlayerDisplayName = (player) => {
        return player.username || player.name || `Player ${player.id}`;
    };

    const allPlayers = Array.from(playerStates.values()).concat(
        // Include leaving players for animation
        Array.from(animatingPlayers)
            .filter(key => key.startsWith('leave-'))
            .map(key => ({ id: key.replace('leave-', ''), username: 'Rời phòng...', isLeaving: true }))
    );

    return (
        <div className="player-list">
            <div className="player-list-header">
                <h3>
                    <FiUser />
                    Người chơi ({roomPlayers.length}/{currentRoom?.maxPlayers || 10})
                </h3>
            </div>

            <div className="player-list-content">
                {allPlayers.map(player => {
                    const isJoining = animatingPlayers.has(`join-${player.id}`);
                    const isLeaving = animatingPlayers.has(`leave-${player.id}`) || player.isLeaving;
                    const isHost = isPlayerHost(player.id);

                    return (
                        <div
                            key={player.id}
                            className={`player-item ${isJoining ? 'joining' : ''} ${isLeaving ? 'leaving' : ''} ${isHost ? 'host' : ''}`}
                        >
                            <div className="player-avatar">
                                {isHost && <FaCrown className="host-crown" />}
                                <FiUser />
                            </div>

                            <div className="player-info">
                                <span className="player-name">
                                    {getPlayerDisplayName(player)}
                                    {isHost && <span className="host-badge">Host</span>}
                                </span>
                                <span className="player-status">
                                    {isLeaving ? 'Đang rời...' : 'Sẵn sàng'}
                                </span>
                            </div>

                            {isJoining && (
                                <div className="join-indicator">
                                    <span>Vào phòng</span>
                                </div>
                            )}
                        </div>
                    );
                })}

                {roomPlayers.length === 0 && (
                    <div className="empty-player-list">
                        <FiUser size={48} />
                        <p>Chưa có người chơi nào</p>
                        <span>Chia sẻ mã phòng để mời bạn bè!</span>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PlayerList;

import { useState, useEffect } from 'react';
import leaderboardApi from '../../../services/leaderboard-api';
import topicApi from '../../../services/topic-api';
import '../../../styles/pages/leaderboard.css';

function Leaderboard() {
    const [topics, setTopics] = useState([]);
    const [selectedTopic, setSelectedTopic] = useState(null);
    const [leaderboard, setLeaderboard] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchTopics();
    }, []);

    useEffect(() => {
        if (selectedTopic) {
            fetchLeaderboard(selectedTopic);
        }
    }, [selectedTopic]);

    const fetchTopics = async () => {
        try {
            const result = await topicApi.getAll();
            if (result.success && result.data.length > 0) {
                setTopics(result.data);
                setSelectedTopic(result.data[0].id);
            }
        } catch (err) {
            setError('Không thể tải danh sách chủ đề');
        }
    };

    const fetchLeaderboard = async (topicId) => {
        setLoading(true);
        setError('');
        try {
            const result = await leaderboardApi.getLeaderboardByTopic(topicId);
            if (result.success) {
                setLeaderboard(result.data);
            } else {
                setError(result.error);
            }
        } catch (err) {
            setError('Không thể tải bảng xếp hạng');
        } finally {
            setLoading(false);
        }
    };

    const getMedalIcon = (rank) => {
        if (rank === 1) return <FaTrophy style={{ color: '#FFD700' }} />;
        if (rank === 2) return <FaTrophy style={{ color: '#C0C0C0' }} />;
        if (rank === 3) return <FaTrophy style={{ color: '#CD7F32' }} />;
        return null;
    };

    const getTopicName = () => {
        const topic = topics.find(t => t.id === selectedTopic);
        return topic?.name || 'Tất cả';
    };

    return (
        <div className="lb-layout">
            <Decoration />
            <main className="lb-content">
                <div className="lb-container">
                    <div className="lb-header">
                        <div className="lb-title-section">
                            <FaTrophy className="lb-title-icon" />
                            <h1 className="lb-title">Bảng Xếp Hạng</h1>
                        </div>
                        <p className="lb-subtitle">Top 20 người chơi xuất sắc nhất</p>
                    </div>

                    <div className="lb-filter-section">
                        <label className="lb-filter-label">
                            <FiTarget />
                            Chủ đề:
                        </label>
                        <select
                            className="lb-filter-select"
                            value={selectedTopic || ''}
                            onChange={(e) => setSelectedTopic(Number(e.target.value))}
                        >
                            {topics.map(topic => (
                                <option key={topic.id} value={topic.id}>
                                    {topic.name}
                                </option>
                            ))}
                        </select>
                    </div>

                    {loading ? (
                        <div className="lb-loading">
                            <div className="lb-spinner"></div>
                            <p>Đang tải bảng xếp hạng...</p>
                        </div>
                    ) : error ? (
                        <div className="lb-error">
                            <p>{error}</p>
                        </div>
                    ) : leaderboard.length === 0 ? (
                        <div className="lb-empty">
                            <FaMedal className="lb-empty-icon" />
                            <p>Chưa có dữ liệu xếp hạng cho chủ đề này</p>
                        </div>
                    ) : (
                        <>
                            <div className="lb-topic-name">
                                Bảng xếp hạng: <strong>{getTopicName()}</strong>
                            </div>
                            <div className="lb-table-container">
                                <table className="lb-table">
                                    <thead>
                                        <tr>
                                            <th>Hạng</th>
                                            <th>Người chơi</th>
                                            <th>Điểm TB</th>
                                            <th>Số trận</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {leaderboard.map((entry) => (
                                            <tr key={entry.userId} className={`lb-row rank-${entry.rank}`}>
                                                <td className="lb-rank">
                                                    {getMedalIcon(entry.rank) || `#${entry.rank}`}
                                                </td>
                                                <td className="lb-player">
                                                    <div className="lb-player-info">
                                                        <div className="lb-avatar">
                                                            {entry.username.charAt(0).toUpperCase()}
                                                        </div>
                                                        <span className="lb-username">{entry.username}</span>
                                                    </div>
                                                </td>
                                                <td className="lb-score">{entry.averageScore.toFixed(2)}</td>
                                                <td className="lb-games">{entry.gamesPlayed}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </>
                    )}
                </div>
            </main>
        </div>
    );
}

export default Leaderboard;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAIGenerator } from '../hooks/use-aigenerator';
import teacherApi from '../services/teacher-api';
import '../../../styles/features/teacher/aiquestion-generator.css';

const AIQuestionGenerator = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedTopic, setSelectedTopic] = useState('');
    const [selectedExam, setSelectedExam] = useState('');
    const [topics, setTopics] = useState([]);
    const [exams, setExams] = useState([]);
    const [filteredExams, setFilteredExams] = useState([]);
    const [loadingTopics, setLoadingTopics] = useState(true);
    const { loading, generatedQuestions, generateQuestions, setGeneratedQuestions } = useAIGenerator();
    const navigate = useNavigate();

    useEffect(() => {
        const loadData = async () => {
            try {
                const [topicsRes, examsRes] = await Promise.all([
                    teacherApi.getAllTopics(),
                    teacherApi.getAllExams()
                ]);
                setTopics(topicsRes.data || []);
                setExams(examsRes.data || []);
            } catch (error) {
                toast.error('Không thể tải dữ liệu');
            } finally {
                setLoadingTopics(false);
            }
        };
        loadData();
    }, []);

    useEffect(() => {
        if (selectedTopic) {
            setFilteredExams(exams.filter(e => e.topicId === parseInt(selectedTopic)));
            setSelectedExam('');
        } else {
            setFilteredExams(exams);
        }
    }, [selectedTopic, exams]);

    const handleGenerate = async (prompt) => {
        if (!selectedExam) {
            toast.error('Vui lòng chọn bộ đề trước');
            return;
        }
        
        const result = await generateQuestions(selectedExam, prompt);
        
        if (result.success) {
            toast.success(`${result.message || `Đã tạo ${result.totalGenerated} câu hỏi thành công!`}`);
        } else {
            toast.error('Không thể tạo câu hỏi: ' + result.error);
        }
    };

    const handleConfirm = () => {
        toast.success(`Đã lưu ${generatedQuestions.length} câu hỏi thành công!`);
        setIsModalOpen(false);
        setGeneratedQuestions([]);
        navigate('/teacher/questions');
    };

    const handleEdit = (index, editedQuestion) => {
        const updated = [...generatedQuestions];
        updated[index] = editedQuestion;
        setGeneratedQuestions(updated);
    };

    const handleDelete = (index) => {
        const updated = generatedQuestions.filter((_, i) => i !== index);
        setGeneratedQuestions(updated);
        toast.info(`Đã xóa câu hỏi. Còn lại ${updated.length} câu hỏi.`);
    };

    // Prompt examples
    const promptExamples = [
        {
            icon: <FiBook />,
            title: 'Trắc nghiệm cơ bản',
            text: 'Tạo 5 câu hỏi trắc nghiệm về [tên bộ đề], mỗi câu có 4 đáp án, độ khó trung bình'
        },
        {
            icon: <FiBook />,
            title: 'Câu hỏi nâng cao',
            text: 'Tạo 10 câu hỏi về [tên bộ đề] với độ khó cao, bao gồm cả câu hỏi tình huống và phân tích'
        },
        {
            icon: <FiZap />,
            title: 'Đa dạng định dạng',
            text: 'Tạo 8 câu hỏi về [tên bộ đề], bao gồm: 4 câu trắc nghiệm, 2 câu đúng/sai, 2 câu nhiều đáp án đúng'
        }
    ];

    const handleUseExample = (exampleText) => {
        if (!selectedExam) {
            toast.warning('Vui lòng chọn bộ đề trước');
            return;
        }
        
        const topicName = topics.find(t => t.id === parseInt(selectedTopic))?.name || 'chủ đề';
        const filledText = exampleText.replace('[chủ đề]', topicName);
        
        navigator.clipboard.writeText(filledText);
        toast.success('Đã copy mẫu prompt!');
        setIsModalOpen(true);
    };

    return (
        <div className="ai-generator-page">
            <div className="ai-page-header">
                <div>
                    <h1><FiZap /> Tạo câu hỏi bằng AI</h1>
                    <p className="ai-subtitle">Sử dụng AI để tự động tạo câu hỏi trắc nghiệm chất lượng cao</p>
                </div>
            </div>

            <div className="ai-generator-content">
                <div className="ai-selection-row">
                    <div className="ai-topic-selection">
                        <label>
                            <FiBook /> Chọn chủ đề:
                        </label>
                        <select 
                            value={selectedTopic} 
                            onChange={(e) => setSelectedTopic(e.target.value)}
                            disabled={loadingTopics}
                        >
                            <option value="">-- Chọn chủ đề --</option>
                            {topics.map(topic => (
                                <option key={topic.id} value={topic.id}>{topic.name}</option>
                            ))}
                        </select>
                    </div>

                    {selectedTopic && (
                        <div className="ai-topic-selection">
                            <label>
                                <FiFileText /> Chọn bộ đề:
                            </label>
                            <select 
                                value={selectedExam} 
                                onChange={(e) => {
                                    setSelectedExam(e.target.value);
                                    if (e.target.value) {
                                        const exam = filteredExams.find(e => e.id === parseInt(e.target.value));
                                        toast.success(`Đã chọn bộ đề: ${exam?.title || ''}`);
                                    }
                                }}
                                className={filteredExams.length === 0 ? 'empty' : ''}
                            >
                                <option value="">
                                    {filteredExams.length === 0 ? 'Chưa có bộ đề nào' : '-- Chọn bộ đề --'}
                                </option>
                                {filteredExams.map(exam => (
                                    <option key={exam.id} value={exam.id}>{exam.title}</option>
                                ))}
                            </select>
                            {filteredExams.length === 0 && (
                                <div className="topic-warning">
                                    <span>Chủ đề này chưa có bộ đề nào.</span>
                                    <button 
                                        onClick={() => navigate('/teacher/exams')}
                                        className="btn-create-topic"
                                    >
                                        Tạo bộ đề ngay
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="ai-prompt-suggestions">
                    <h3><FiBook /> Gợi ý mẫu Prompt</h3>
                    <p className="suggestions-desc">Chọn một mẫu prompt bên dưới để bắt đầu nhanh chóng:</p>
                    
                    <div className="prompt-examples-grid">
                        {promptExamples.map((example, index) => (
                            <div key={index} className="prompt-example-card">
                                <div className="example-icon">{example.icon}</div>
                                <h4>{example.title}</h4>
                                <p>{example.text}</p>
                                <button 
                                    onClick={() => handleUseExample(example.text)}
                                    disabled={!selectedExam}
                                    className="btn-use-example"
                                >
                                    Sử dụng mẫu này
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="ai-action-section">
                    <button 
                        onClick={() => setIsModalOpen(true)} 
                        disabled={!selectedExam}
                        className="btn-open-ai"
                    >
                        <FiZap /> Mở AI Generator
                    </button>
                    {!selectedExam && (
                        <p className="ai-hint">Vui lòng chọn bộ đề trước khi tạo câu hỏi</p>
                    )}
                </div>
            </div>

            <AIPromptModal
                isOpen={isModalOpen}
                onClose={() => {
                    setIsModalOpen(false);
                    setGeneratedQuestions([]);
                }}
                onConfirm={generatedQuestions.length ? handleConfirm : handleGenerate}
                loading={loading}
                generatedQuestions={generatedQuestions}
                onEdit={handleEdit}
                onDelete={handleDelete}
            />
        </div>
    );
};

export default AIQuestionGenerator;

import { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-toastify';
import teacherApi from '../services/teacher-api';
import '../../../styles/features/teacher/management.css';

const TopicManagement = () => {
    const [topics, setTopics] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [editingTopic, setEditingTopic] = useState(null);
    const [formData, setFormData] = useState({ name: '', description: '' });
    
    // Pagination states
    const [currentPage, setCurrentPage] = useState(0);
    const [totalPages, setTotalPages] = useState(0);
    const [totalElements, setTotalElements] = useState(0);
    const [sortOrder, setSortOrder] = useState('asc');

    useEffect(() => {
        loadTopics();
    }, [currentPage, sortOrder, searchTerm]);

    const loadTopics = useCallback(async () => {
        try {
            setLoading(true);
            const sortParam = `name,${sortOrder}`;
            const response = await teacherApi.searchTopics(searchTerm, currentPage, 10, sortParam);
            
            if (response.data) {
                const pageData = response.data;
                setTopics(pageData.content || []);
                setTotalPages(pageData.totalPages || 0);
                setTotalElements(pageData.totalElements || 0);
            }
        } catch (error) {
            console.error('Error loading topics:', error);
            toast.error('Không thể tải danh sách chủ đề');
            setTopics([]);
        } finally {
            setLoading(false);
        }
    }, [currentPage, sortOrder, searchTerm]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingTopic) {
                await teacherApi.updateTopic(editingTopic.id, formData);
                toast.success('Cập nhật chủ đề thành công');
            } else {
                await teacherApi.createTopic(formData);
                toast.success('Tạo chủ đề thành công');
            }
            setShowModal(false);
            setFormData({ name: '', description: '' });
            setEditingTopic(null);
            // Reset về trang đầu sau khi tạo/cập nhật
            setCurrentPage(0);
            loadTopics();
        } catch (error) {
            toast.error(editingTopic ? 'Không thể cập nhật chủ đề' : 'Không thể tạo chủ đề');
        }
    };

    const handleSearch = useCallback((value) => {
        setSearchTerm(value);
        setCurrentPage(0); // Reset về trang đầu khi search
    }, []);

    const handleSort = () => {
        setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
        setCurrentPage(0);
    };

    const handlePageChange = (newPage) => {
        if (newPage >= 0 && newPage < totalPages) {
            setCurrentPage(newPage);
        }
    };

    const handleEdit = (topic) => {
        setEditingTopic(topic);
        setFormData({ name: topic.name, description: topic.description });
        setShowModal(true);
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Bạn có chắc muốn xóa chủ đề này?')) return;
        try {
            await teacherApi.deleteTopic(id);
            toast.success('Xóa chủ đề thành công');
            loadTopics();
        } catch (error) {
            toast.error('Không thể xóa chủ đề');
        }
    };

    const getSortIcon = () => {
        return sortOrder === 'asc' ? '↑' : '↓';
    };

    const getRowNumber = (index) => {
        return currentPage * 10 + index + 1;
    };

    if (loading && topics.length === 0) return <div className="loading">Đang tải...</div>;

    return (
        <div className="management-page">
            <div className="management-header">
                <h1>Quản lý Chủ đề</h1>
                <button className="btn-primary" onClick={() => { setShowModal(true); setEditingTopic(null); setFormData({ name: '', description: '' }); }}>
                    <FiPlus /> Thêm chủ đề
                </button>
            </div>

            <div className="filter-section">
                <div className="search-bar-compact">
                    <FiSearch />
                    <input
                        type="text"
                        placeholder="Tìm kiếm theo tên hoặc mô tả..."
                        value={searchTerm}
                        onChange={(e) => handleSearch(e.target.value)}
                    />
                </div>
            </div>

            <div className="table-info">
                <span>Hiển thị {topics.length > 0 ? currentPage * 10 + 1 : 0} - {Math.min((currentPage + 1) * 10, totalElements)} trong tổng số {totalElements} chủ đề</span>
            </div>

            <div className="table-container">
                <table>
                    <thead>
                        <tr>
                            <th style={{ width: '80px' }}>STT</th>
                            <th style={{ cursor: 'pointer' }} onClick={handleSort}>
                                Tên chủ đề {getSortIcon()}
                            </th>
                            <th>Mô tả</th>
                            <th style={{ width: '120px' }}>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan="4" style={{ textAlign: 'center', padding: '2rem' }}>
                                    <div className="spinner-small"></div>
                                    Đang tải...
                                </td>
                            </tr>
                        ) : topics.length === 0 ? (
                            <tr>
                                <td colSpan="4" style={{ textAlign: 'center', padding: '2rem' }}>
                                    {searchTerm ? 'Không tìm thấy chủ đề phù hợp' : 'Chưa có chủ đề nào'}
                                </td>
                            </tr>
                        ) : (
                            topics.map((topic, index) => (
                                <tr key={topic.id}>
                                    <td style={{ fontWeight: '600', color: 'var(--text-secondary)' }}>
                                        {getRowNumber(index)}
                                    </td>
                                    <td style={{ fontWeight: '600' }}>{topic.name}</td>
                                    <td style={{ maxWidth: '400px' }}>{topic.description}</td>
                                    <td>
                                        <div className="action-buttons">
                                            <button className="btn-edit" onClick={() => handleEdit(topic)} title="Sửa">
                                                <FiEdit2 />
                                            </button>
                                            <button className="btn-delete" onClick={() => handleDelete(topic.id)} title="Xóa">
                                                <FiTrash2 />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {totalPages > 1 && (
                <div className="pagination">
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage - 1)}
                        disabled={currentPage === 0}
                    >
                        <FiChevronLeft /> Trước
                    </button>
                    
                    <div className="pagination-pages">
                        {[...Array(totalPages)].map((_, index) => {
                            // Hiển thị trang đầu, cuối và các trang xung quanh trang hiện tại
                            if (
                                index === 0 || 
                                index === totalPages - 1 || 
                                (index >= currentPage - 1 && index <= currentPage + 1)
                            ) {
                                return (
                                    <button
                                        key={index}
                                        className={`pagination-page ${index === currentPage ? 'active' : ''}`}
                                        onClick={() => handlePageChange(index)}
                                    >
                                        {index + 1}
                                    </button>
                                );
                            } else if (index === currentPage - 2 || index === currentPage + 2) {
                                return <span key={index} className="pagination-ellipsis">...</span>;
                            }
                            return null;
                        })}
                    </div>
                    
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage + 1)}
                        disabled={currentPage === totalPages - 1}
                    >
                        Sau <FiChevronRight />
                    </button>
                </div>
            )}

            {showModal && (
                <div className="modal-overlay" onClick={() => setShowModal(false)}>
                    <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                        <h2>{editingTopic ? 'Cập nhật chủ đề' : 'Thêm chủ đề mới'}</h2>
                        <form onSubmit={handleSubmit}>
                            <div className="form-group">
                                <label>Tên chủ đề *</label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label>Mô tả</label>
                                <textarea
                                    value={formData.description}
                                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                    rows={4}
                                />
                            </div>
                            <div className="modal-actions">
                                <button type="button" className="btn-cancel" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-submit">
                                    {editingTopic ? 'Cập nhật' : 'Tạo mới'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default TopicManagement;

import { useState, useCallback, useEffect } from 'react';
import profileApi from '../services/profile-api';

export const useProfileEdit = (profileData, setProfileData) => {
    const [isEditing, setIsEditing] = useState(false);
    const [formData, setFormData] = useState({
        fullName: '',
        phoneNumber: '',
        address: '',
        email: '',
        dob: ''
    });
    const [formErrors, setFormErrors] = useState({});
    const [updateLoading, setUpdateLoading] = useState(false);

    // Update formData when profileData changes
    useEffect(() => {
        if (profileData) {
            setFormData({
                fullName: profileData.fullName || '',
                phoneNumber: profileData.phoneNumber || '',
                address: profileData.address || '',
                email: profileData.email || '',
                dob: profileData.dob ? profileData.dob.split('T')[0] : '' // Format date for input
            });
        }
    }, [profileData]);

    const validateProfile = useCallback(() => {
        const errors = {};
        if (!formData.fullName.trim()) errors.fullName = 'Vui lòng nhập họ tên';
        if (!formData.email.trim()) errors.email = 'Vui lòng nhập email';
        else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) errors.email = 'Email không hợp lệ';
        if (!formData.phoneNumber.trim()) errors.phoneNumber = 'Vui lòng nhập số điện thoại';
        else if (!/^\d{10}$/.test(formData.phoneNumber)) errors.phoneNumber = 'Số điện thoại phải có 10 chữ số';
        if (!formData.address.trim()) errors.address = 'Vui lòng nhập địa chỉ';
        if (!formData.dob) errors.dob = 'Vui lòng chọn ngày sinh';
        else {
            const birthDate = new Date(formData.dob);
            const today = new Date();
            const age = today.getFullYear() - birthDate.getFullYear();
            if (age < 13) errors.dob = 'Bạn phải từ 13 tuổi trở lên';
            if (birthDate > today) errors.dob = 'Ngày sinh không được lớn hơn ngày hiện tại';
        }
        setFormErrors(errors);
        return Object.keys(errors).length === 0;
    }, [formData]);

    const handleProfileChange = useCallback((e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setFormErrors((prev) => ({ ...prev, [name]: '' }));
    }, []);

    const handleUpdateProfile = useCallback(async (setError, setSuccessMessage) => {
        if (!validateProfile()) return;

        try {
            setUpdateLoading(true);
            setError('');
            setSuccessMessage('');

            const updateData = {
                fullName: formData.fullName,
                phoneNumber: formData.phoneNumber,
                address: formData.address,
                email: formData.email,
                dob: formData.dob // Thêm dob vào request
            };

            const result = await profileApi.updateProfile(updateData);

            if (result.isSuccess) {
                setProfileData(result.data);
                setSuccessMessage('Cập nhật thông tin thành công!');
                setTimeout(() => setSuccessMessage(''), 3000);
                setIsEditing(false);
            } else {
                setError(result.message);
            }
        } catch (error) {
            setError(error.message || 'Không thể cập nhật thông tin');
        } finally {
            setUpdateLoading(false);
        }
    }, [formData, profileData, validateProfile, setProfileData]);

    return {
        isEditing,
        setIsEditing,
        formData,
        formErrors,
        updateLoading,
        handleProfileChange,
        handleUpdateProfile
    };
};

import { useState, useEffect } from 'react';
import topicApi from '../services/topic-api';

export const useTopics = () => {
    const [topics, setTopics] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    // Mock data for development when API is not available
    const mockTopics = [
        { id: 1, name: 'Toán học', description: 'Câu hỏi về toán học cơ bản và nâng cao' },
        { id: 2, name: 'Văn học', description: 'Câu hỏi về văn học Việt Nam và thế giới' },
        { id: 3, name: 'Lịch sử', description: 'Câu hỏi về lịch sử Việt Nam và thế giới' },
        { id: 4, name: 'Địa lý', description: 'Câu hỏi về địa lý tự nhiên và kinh tế' },
        { id: 5, name: 'Khoa học', description: 'Câu hỏi về vật lý, hóa học, sinh học' },
        { id: 6, name: 'Tiếng Anh', description: 'Câu hỏi về ngữ pháp và từ vựng tiếng Anh' },
        { id: 7, name: 'Thể thao', description: 'Câu hỏi về thể thao trong nước và quốc tế' },
        { id: 8, name: 'Giải trí', description: 'Câu hỏi về phim ảnh, âm nhạc, game' },
    ];

    const loadTopics = async () => {
        try {
            setLoading(true);
            setError('');
            const result = await topicApi.getAll();

            if (result.success && Array.isArray(result.data)) {
                if (result.data.length > 0) {
                    setTopics(result.data);
                } else {
                    setTopics(mockTopics);
                }
            } else {
                setTopics(mockTopics);
            }
        } catch (err) {
            setError('Không thể tải danh sách chủ đề');
            setTopics(mockTopics);
        } finally {
            setLoading(false);
        }
    };

    const getTopicById = (topicId) => {
        return topics.find(topic => topic.id.toString() === topicId.toString());
    };

    const searchTopics = async (query) => {
        try {
            const result = await topicApi.search(query);
            return result.success && Array.isArray(result.data) ? result.data : [];
        } catch (err) {
            console.error('Error searching topics:', err);
            return [];
        }
    };

    const searchTopicsPaginated = async (keyword = '', page = 0, size = 10, sort = 'id,desc') => {
        try {
            const result = await topicApi.searchPaginated(keyword, page, size, sort);
            return result.success ? result.data : { content: [], page: 0, size: 10, totalElements: 0, totalPages: 0 };
        } catch (err) {
            return { content: [], page: 0, size: 10, totalElements: 0, totalPages: 0 };
        }
    };

    const refreshTopics = () => {
        loadTopics();
    };

    useEffect(() => {
        loadTopics();
    }, []);

    return {
        topics,
        loading,
        error,
        getTopicById,
        searchTopics,
        searchTopicsPaginated,
        refreshTopics,
        setError
    };
};

export default useTopics;

import { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import authApi from '../../services/auth-api';
import authStore from '../../stores/auth-store';
import { usePopup } from '@shared/hooks/use-popup';
import '../../styles/pages/auth/forgot-password.css';

function ForgotPassword() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const { popup, showSuccess, showError, hidePopup } = usePopup();
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { isAuthenticated } = authStore();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard', { replace: true });
    }
  }, [isAuthenticated, navigate]);

  const handleChange = useCallback((e) => {
    setEmail(e.target.value);
    setError('');
    setSuccessMessage('');
  }, []);

  const validateEmail = useCallback(() => {
    if (!email.trim()) {
      setError('Vui lòng nhập email');
      return false;
    }
    if (!/\S+@\S+\.\S+/.test(email)) {
      setError('Email không hợp lệ');
      return false;
    }
    if (email.length > 255) {
      setError('Email quá dài (tối đa 255 ký tự)');
      return false;
    }
    return true;
  }, [email]);

  const handleSubmit = useCallback(
    async (e) => {
      e.preventDefault();
      if (!validateEmail()) return;

      setIsSubmitting(true);
      setError('');
      setSuccessMessage('');

      try {
        await authApi.forgotPassword(email);
        setSuccessMessage('Mật khẩu mới đã được gửi đến email của bạn!');
        showSuccess('Vui lòng kiểm tra hộp thư để lấy mật khẩu mới.');
      } catch (error) {
        const errorMessage = error.response?.data?.message || error.message || 'Có lỗi xảy ra, vui lòng thử lại';
        setError(errorMessage);
        showError(errorMessage);
      } finally {
        setIsSubmitting(false);
      }
    },
    [email, validateEmail]
  );

  return (
    <div className="fp-container">
      <Decoration />
      <PopupNotification
        type={popup.type}
        title={popup.title}
        message={popup.message}
        isVisible={popup.isVisible}
        onClose={hidePopup}
        showConfirm={popup.showConfirm}
        onConfirm={popup.onConfirm}
        onCancel={popup.onCancel}
        confirmText={popup.confirmText}
        cancelText={popup.cancelText}
      />
      <div className="fp-card">
        {!successMessage && (
          <Link to="/login" className="fp-back-button" aria-label="Quay lại trang đăng nhập">
            <IoArrowBackSharp size={20} />
          </Link>
        )}

        <div className="fp-header">
          <div className="fp-logo">
            <div className="fp-logo-icon">
              <FaBrain size={40} color="#dd797a" />
            </div>
            <span className="fp-logo-text">BrainGame</span>
          </div>
          <h1 className="fp-title">
            {successMessage ? 'Email đã được gửi' : 'Quên mật khẩu'}
          </h1>
        </div>

        {successMessage && (
          <div className="fp-success-container">
            <div className="fp-success-message">
              <span className="fp-success-icon">✓</span>
              <span>{successMessage}</span>
            </div>
            <div className="fp-success-actions">
              <Link to="/login" className="fp-submit-button">
                Quay lại trang đăng nhập
              </Link>
            </div>
          </div>
        )}

        {!successMessage && (
          <>

            <form className="fp-form" onSubmit={handleSubmit}>
              <div className="fp-form-group">
                <label className="fp-form-label" htmlFor="email">
                  <FaEnvelope className="fp-input-icon" />
                  <span>Email</span>
                </label>
                <div className="fp-input-wrapper">
                  <input
                    type="email"
                    id="email"
                    name="email"
                    className={`fp-form-input ${error ? 'fp-input-error' : ''}`}
                    value={email}
                    onChange={handleChange}
                    placeholder="Nhập email của bạn"
                    disabled={isSubmitting}
                    autoComplete="email"
                  />
                  {error && (
                    <div className="fp-error-message">
                      <FaExclamationCircle size={14} />
                      <span>{error}</span>
                    </div>
                  )}
                </div>
              </div>

              <button
                className={`fp-submit-button ${isSubmitting ? 'loading' : ''}`}
                type="submit"
                disabled={isSubmitting}
              >
                {isSubmitting ? (
                  <>
                    <div className="fp-loading-spinner-container">
                      <div className="fp-loading-spinner"></div>
                    </div>
                    <span className="fp-button-text">Đang gửi email...</span>
                  </>
                ) : (
                  <span>Gửi email đặt lại mật khẩu</span>
                )}
              </button>
            </form>

            <div className="fp-divider">
              <span>hoặc</span>
            </div>

            <div className="fp-login-link">
              <span>Đã nhớ mật khẩu?</span>
              <Link to="/login">Đăng nhập ngay</Link>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default ForgotPassword;

import { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import authApi from '../../services/auth-api';
import '../../styles/pages/auth/login.css';
import { usePopup } from '@shared/hooks/use-popup';
import authStore from '../../stores/auth-store';
import { jwtDecode } from 'jwt-decode';

function Login() {
    const [formData, setFormData] = useState({ username: '', password: '' });
    const [errors, setErrors] = useState({});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const { popup, showSuccess, showError, showWarning, hidePopup } = usePopup();
    const [showPassword, setShowPassword] = useState(false);
    const navigate = useNavigate();

    const isAuthenticated = authStore((state) => state.isAuthenticated);
    const user = authStore((state) => state.user);

    useEffect(() => {
        if (isAuthenticated && user?.role) {
            let redirectPath = '/dashboard';
            if (user.role === 'ADMIN') redirectPath = '/admin/dashboard';
            else if (user.role === 'TEACHER') redirectPath = '/teacher/dashboard';
            else if (user.role === 'PLAYER') redirectPath = '/dashboard';
            navigate(redirectPath, { replace: true });
        }
    }, [isAuthenticated, user, navigate]);

    const validateForm = useCallback(() => {
        const newErrors = {};
        const username = formData.username.trim();
        const password = formData.password;

        if (!username) {
            newErrors.username = 'Vui lòng nhập tên đăng nhập';
        } else if (username.length < 3) {
            newErrors.username = 'Tên đăng nhập phải có ít nhất 3 ký tự';
        }

        if (!password) {
            newErrors.password = 'Vui lòng nhập mật khẩu';
        } else if (password.length < 6) {
            newErrors.password = 'Mật khẩu phải có ít nhất 6 ký tự';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    }, [formData]);

    const handleChange = useCallback((e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setErrors((prev) => ({ ...prev, [name]: '' }));
    }, []);

    const handleSubmit = useCallback(
        async (e) => {
            e.preventDefault();
            
            if (!validateForm()) {
                return;
            }

            setIsSubmitting(true);

            try {
                const response = await authApi.login({
                    username: formData.username,
                    password: formData.password,
                });
                
                const userData = response.data;
                const accessToken = userData?.accessToken;
                
                // Decode JWT to get typeAccount
                const decoded = jwtDecode(accessToken);
                const userRole = decoded?.typeAccount;
                
                showSuccess('Đăng nhập thành công!');
                
                let redirectPath = '/dashboard';
                if (userRole === 'ADMIN') redirectPath = '/admin/dashboard';
                else if (userRole === 'TEACHER') redirectPath = '/teacher/dashboard';
                else if (userRole === 'PLAYER') redirectPath = '/dashboard';
                
                setTimeout(() => navigate(redirectPath, { replace: true }), 1000);
            } catch (error) {
                const status = error.response?.status;
                const errorMessage = error.response?.data?.message || error.message || 'Đăng nhập thất bại';
                
                // Xử lý trường hợp email chưa được xác thực
                if (status === 403 && errorMessage.includes('Email not verified')) {
                    showWarning('Email chưa được xác thực. Vui lòng kiểm tra email và xác thực tài khoản trước khi đăng nhập.');
                } else {
                    showError(errorMessage);
                }
                setIsSubmitting(false);
            }
        },
        [formData, validateForm, navigate]
    );

    const togglePasswordVisibility = useCallback(() => {
        setShowPassword((prev) => !prev);
    }, []);

    return (
        <div className="login-container">
            <Decoration />
            <PopupNotification
                type={popup.type}
                title={popup.title}
                message={popup.message}
                isVisible={popup.isVisible}
                onClose={hidePopup}
                showConfirm={popup.showConfirm}
                onConfirm={popup.onConfirm}
                onCancel={popup.onCancel}
                confirmText={popup.confirmText}
                cancelText={popup.cancelText}
            />
            <div className="login-card">
                <div className="login-header">
                    <div className="login-logo">
                        <FaBrain size={40} color="#dd797a" />
                        <span className="logo-text">BrainGame</span>
                    </div>
                    <h1 className="login-title">Đăng nhập</h1>
                </div>

                <form className="login-form" onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label className="login-label" htmlFor="username">
                            <FaUser size={16} color="#667eea" />
                            Tên đăng nhập
                        </label>
                        <div className="input-wrapper">
                            <input
                                type="text"
                                id="username"
                                name="username"
                                className={`input ${errors.username ? 'input-error' : ''}`}
                                value={formData.username}
                                onChange={handleChange}
                                placeholder="Nhập tên đăng nhập hoặc email"
                                disabled={isSubmitting}
                                autoComplete="username"
                            />
                        </div>
                        {errors.username && (
                            <div className="error-message">
                                <FaExclamationCircle size={16} color="#dc2626" />
                                <span className="error-text">{errors.username}</span>
                            </div>
                        )}
                    </div>

                    <div className="form-group">
                        <label className="login-label" htmlFor="password">
                            <FaLock size={16} color="#667eea" />
                            Mật khẩu
                        </label>
                        <div className="input-wrapper password-wrapper">
                            <input
                                type={showPassword ? 'text' : 'password'}
                                id="password"
                                name="password"
                                className={`input ${errors.password ? 'input-error' : ''}`}
                                value={formData.password}
                                onChange={handleChange}
                                placeholder="Nhập mật khẩu"
                                disabled={isSubmitting}
                                autoComplete="current-password"
                            />
                            <button
                                type="button"
                                className="password-toggle"
                                onClick={togglePasswordVisibility}
                                disabled={isSubmitting}
                                aria-label={showPassword ? 'Ẩn mật khẩu' : 'Hiện mật khẩu'}
                            >
                                {showPassword ? (
                                    <FaEyeSlash size={20} color="#718096" />
                                ) : (
                                    <FaEye size={20} color="#718096" />
                                )}
                            </button>
                        </div>
                        <div className="forgot-password">
                            <Link to="/forgot-password">Quên mật khẩu?</Link>
                        </div>
                        {errors.password && (
                            <div className="error-message">
                                <FaExclamationCircle size={16} color="#dc2626" />
                                <span className="error-text">{errors.password}</span>
                            </div>
                        )}
                    </div>

                    <button
                        className={`submit-button ${isSubmitting ? 'loading' : ''}`}
                        type="submit"
                        disabled={isSubmitting}
                    >
                        {isSubmitting ? (
                            <span className="button-text">Đang đăng nhập...</span>
                        ) : (
                            <span>Đăng nhập</span>
                        )}
                    </button>
                </form>

                <div className="divider">
                    <span>hoặc</span>
                </div>
                
                <div className="register-link">
                    <span>Chưa có tài khoản? </span>
                    <Link to="/register">Đăng ký ngay</Link>
                </div>
            </div>
        </div>
    );
}

export default Login;

import { useState, useCallback, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { FaEnvelope, FaHome, FaLock, FaPhoneAlt, FaUser, FaCalendarAlt } from 'react-icons/fa';
import authApi from '../../services/auth-api';
import authStore from '../../stores/auth-store';
import { usePopup } from '@shared/hooks/use-popup';
import '../../styles/pages/auth/register.css';

function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    username: '',
    fullName: '',
    email: '',
    phoneNumber: '',
    address: '',
    password: '',
    confirmPassword: '',
    dob: '',
  });
  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { popup, showSuccess, showError, hidePopup } = usePopup();
  const firstErrorInputRef = useRef(null);
  const { isAuthenticated } = authStore();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard', { replace: true });
    }
  }, [isAuthenticated, navigate]);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    setErrors((prev) => ({ ...prev, [name]: '' }));
  }, []);

  const validateField = useCallback((name, value) => {
    switch (name) {
      case 'username':
        if (!value.trim()) return 'Vui lòng nhập tên người dùng';
        if (value.length < 3) return 'Tên người dùng phải có ít nhất 3 ký tự';
        return '';
      case 'fullName':
        if (!value.trim()) return 'Vui lòng nhập họ tên';
        return '';
      case 'email':
        if (!value) return 'Vui lòng nhập email';
        if (!/\S+@\S+\.\S+/.test(value)) return 'Email không hợp lệ';
        return '';
      case 'phoneNumber':
        if (!value.trim()) return 'Vui lòng nhập số điện thoại';
        if (!/^\d{10}$/.test(value)) return 'Số điện thoại phải có 10 chữ số';
        return '';
      case 'address':
        if (!value.trim()) return 'Vui lòng nhập địa chỉ';
        return '';
      case 'dob':
      {
        if (!value) return 'Vui lòng nhập ngày sinh';
        const birthDate = new Date(value);
        const today = new Date();
        if (birthDate > today) return 'Ngày sinh không thể ở tương lai';
        return '';
      }
      case 'password':
        if (!value) return 'Vui lòng nhập mật khẩu';
        if (value.length < 6) return 'Mật khẩu phải có ít nhất 6 ký tự';
        return '';
      case 'confirmPassword':
        if (value !== formData.password) return 'Mật khẩu không khớp';
        return '';
      default:
        return '';
    }
  }, [formData.password]);

  const validateForm = useCallback(() => {
    const newErrors = {};
    Object.keys(formData).forEach((key) => {
      const error = validateField(key, formData[key]);
      if (error) newErrors[key] = error;
    });
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData, validateField]);

  const handleSubmit = useCallback(
    async (e) => {
      e.preventDefault();
      if (!validateForm()) {
        const firstErrorKey = Object.keys(errors)[0];
        if (firstErrorKey) {
          firstErrorInputRef.current = document.getElementById(firstErrorKey);
          firstErrorInputRef.current?.focus();
        }
        return;
      }

      setIsSubmitting(true);

      try {
        await authApi.register({
          username: formData.username,
          fullName: formData.fullName,
          email: formData.email,
          phoneNumber: formData.phoneNumber,
          address: formData.address,
          dob: formData.dob,
          password: formData.password,
          confirm_password: formData.confirmPassword,
        });

        showSuccess('Đăng ký thành công! Vui lòng kiểm tra email để xác thực tài khoản.');
        setTimeout(() => navigate('/login'), 3000);
      } catch (error) {
        const errorMessage = error.response?.data?.message || error.message || 'Đã xảy ra lỗi. Vui lòng thử lại.';
        if (error.response?.status === 400) {
          const newErrors = {};
          if (error.response?.data?.field === 'email') {
            newErrors.email = 'Email đã tồn tại';
            firstErrorInputRef.current = document.getElementById('email');
          } else if (error.response?.data?.field === 'username') {
            newErrors.username = 'Tên người dùng đã tồn tại';
            firstErrorInputRef.current = document.getElementById('username');
          } else {
            showError(errorMessage);
          }
          setErrors((prev) => ({ ...prev, ...newErrors }));
          firstErrorInputRef.current?.focus();
        } else {
          showError(errorMessage);
        }
      } finally {
        setIsSubmitting(false);
      }
    },
    [formData, validateForm, navigate]
  );

  return (
    <div className="register-container">
      <Decoration />
      <PopupNotification
        type={popup.type}
        title={popup.title}
        message={popup.message}
        isVisible={popup.isVisible}
        onClose={hidePopup}
        showConfirm={popup.showConfirm}
        onConfirm={popup.onConfirm}
        onCancel={popup.onCancel}
        confirmText={popup.confirmText}
        cancelText={popup.cancelText}
      />
      <div className="register-card">
        <div className="register-header">
          <div className="register-logo">
            <div className="logo-icon">
              <FaBrain size={40} color="#dd797a" />
            </div>
            <span className="logo-text">BrainGame</span>
          </div>
          <h1 className="register-title">Đăng ký</h1>
        </div>

        <form className="register-form" onSubmit={handleSubmit}>
          {[
            { name: 'username', label: 'Tên người dùng', icon: FaUser, type: 'text', placeholder: 'Nhập tên người dùng' },
            { name: 'fullName', label: 'Họ tên', icon: FaUser, type: 'text', placeholder: 'Nhập họ tên' },
            { name: 'email', label: 'Email', icon: FaEnvelope, type: 'email', placeholder: 'example@email.com' },
            { name: 'phoneNumber', label: 'Số điện thoại', icon: FaPhoneAlt, type: 'tel', placeholder: 'Nhập số điện thoại (10 chữ số)' },
            { name: 'address', label: 'Địa chỉ', icon: FaHome, type: 'text', placeholder: 'Nhập địa chỉ' },
            { name: 'dob', label: 'Ngày sinh', icon: FaCalendarAlt, type: 'date', placeholder: 'Chọn ngày sinh' },
            { name: 'password', label: 'Mật khẩu', icon: FaLock, type: 'password', placeholder: 'Nhập mật khẩu' },
            { name: 'confirmPassword', label: 'Xác nhận mật khẩu', icon: FaLock, type: 'password', placeholder: 'Nhập lại mật khẩu' },
          ].map(({ name, label, icon: Icon, type, placeholder }) => (
            <div className="form-group" key={name}>
              <label className="register-label" htmlFor={name}>
                <Icon size={16} color="#667eea" />
                {label}
              </label>
              <input
                type={type}
                id={name}
                name={name}
                className={`input ${errors[name] ? 'input-error' : ''}`}
                value={formData[name]}
                onChange={handleChange}
                placeholder={placeholder}
                disabled={isSubmitting}
                autoComplete={name.includes('password') ? name : 'off'}
              />
              {errors[name] && (
                <div className="error-message">
                  <FaExclamationCircle size={16} color="#dc2626" />
                  {errors[name]}
                </div>
              )}
            </div>
          ))}

          <button className="submit-button" type="submit" disabled={isSubmitting}>
            {isSubmitting ? (
              <>
                <div className="loading-spinner"></div>
                Đang đăng ký...
              </>
            ) : (
              <>Đăng ký</>
            )}
          </button>
        </form>

        <div className="divider">
          <span>hoặc</span>
        </div>

        <div className="login-link">
          <span>Đã có tài khoản?</span>
          <Link to="/login">Đăng nhập ngay</Link>
        </div>
      </div>
    </div>
  );
}

export default Register;

import { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import authApi from '../../services/auth-api';
import '../../styles/pages/verify-email.css';

const VerifyEmail = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [status, setStatus] = useState('loading');
  const [message, setMessage] = useState('');

  useEffect(() => {
    const token = searchParams.get('token');

    if (!token) {
      setStatus('error');
      setMessage('Token xác thực không hợp lệ.');
      return;
    }

    handleVerifyEmail(token);
  }, [searchParams]);

  const handleVerifyEmail = async (token) => {
    try {
      const response = await authApi.verifyEmail(token);

      if (response.isSuccess) {
        setStatus('success');
        setMessage('Email đã được xác thực thành công!');

        setTimeout(() => {
          navigate('/login');
        }, 3000);
      } else {
        setStatus('error');
        setMessage(response.message || 'Xác thực email thất bại.');
      }
    } catch (error) {
      setStatus('error');
      setMessage(error.message || 'Có lỗi xảy ra khi xác thực email.');
    }
  };

  const handleGoToLogin = () => {
    navigate('/login');
  };

  const handleResendEmail = async () => {
    setStatus('loading');
    setMessage('Đang gửi lại email...');
    setTimeout(() => {
      setStatus('error');
      setMessage('Vui lòng liên hệ hỗ trợ để gửi lại email xác thực.');
    }, 1000);
  };

  return (
    <div className="verify-email-container">
      <div className="verify-email-card">
        {status === 'loading' && (
          <div className="verify-content loading">
            <FiLoader className="icon spin" />
            <h2>Đang xác thực email...</h2>
            <p>Vui lòng đợi trong giây lát.</p>
          </div>
        )}

        {status === 'success' && (
          <div className="verify-content success">
            <FiCheckCircle className="icon" />
            <h2>Xác thực thành công!</h2>
            <p>{message}</p>
            <p className="redirect-message">Bạn sẽ được chuyển đến trang đăng nhập trong vài giây...</p>
            <button onClick={handleGoToLogin} className="btn-primary">
              Đăng nhập ngay
            </button>
          </div>
        )}

        {status === 'error' && (
          <div className="verify-content error">
            <FiXCircle className="icon" />
            <h2>Xác thực thất bại</h2>
            <p>{message}</p>
            <div className="error-actions">
              <button onClick={handleGoToLogin} className="btn-primary">
                Đăng nhập
              </button>
              <button onClick={handleResendEmail} className="btn-secondary">
                Gửi lại email
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default VerifyEmail;

import { useNavigate } from 'react-router-dom';
import authStore from '../../stores/auth-store';
import '../../styles/pages/dashboard/quick-actions-section.css';

const quickActions = [
    { title: 'Chơi ngay', desc: 'Bắt đầu trò chơi mới', action: (navigate) => navigate('/rooms') },
    { title: 'Xem bảng xếp hạng', desc: 'Top người chơi', action: (navigate) => navigate('/leaderboard') },
    { title: 'Hồ sơ cá nhân', desc: 'Xem thống kê của bạn', action: (navigate) => navigate('/profile') },
];

function QuickActionsSection({ onLogout }) {
    const navigate = useNavigate();
    const { user } = authStore();

    if (!user) {
        return <div className="qa-actions-section">Vui lòng đăng nhập để tiếp tục.</div>;
    }

    return (
        <div className="qa-actions-section">
            <h2 className="qa-section-title">Hành động nhanh</h2>
