import { useState, useEffect } from 'react';
import './PopupNotification.css';

const PopupNotification = ({ 
    type = 'info', 
    title, 
    message, 
    isVisible, 
    onClose, 
    autoClose = true, 
    duration = 4000,
    showConfirm = false,
    onConfirm,
    onCancel,
    confirmText = 'Xác nhận',
    cancelText = 'Hủy'
}) => {
    const [show, setShow] = useState(isVisible);

    useEffect(() => {
        setShow(isVisible);
        
        if (isVisible && autoClose && !showConfirm) {
            const timer = setTimeout(() => {
                handleClose();
            }, duration);
            
            return () => clearTimeout(timer);
        }
    }, [isVisible, autoClose, duration, showConfirm]);

    const handleClose = () => {
        setShow(false);
        setTimeout(() => {
            onClose?.();
        }, 300);
    };

    const handleConfirm = () => {
        onConfirm?.();
        handleClose();
    };

    const handleCancel = () => {
        onCancel?.();
        handleClose();
    };

    const getIcon = () => {
        switch (type) {
            case 'success':
                return <FiCheck />;
            case 'error':
                return <FiAlertCircle />;
            case 'warning':
                return <FiAlertTriangle />;
            default:
                return <FiInfo />;
        }
    };

    if (!isVisible) return null;

    return (
        <div className={`popup-overlay ${show ? 'show' : ''}`}>
            <div className={`popup-notification ${type} ${show ? 'show' : ''}`}>
                <div className="popup-header">
                    <div className="popup-icon">
                        {getIcon()}
                    </div>
                    <div className="popup-content">
                        {title && <h3 className="popup-title">{title}</h3>}
                        <p className="popup-message">{message}</p>
                    </div>
                    {!showConfirm && (
                        <button className="popup-close" onClick={handleClose}>
                            <FiX />
                        </button>
                    )}
                </div>
                
                {showConfirm && (
                    <div className="popup-actions">
                        <button className="popup-btn popup-btn-cancel" onClick={handleCancel}>
                            {cancelText}
                        </button>
                        <button className="popup-btn popup-btn-confirm" onClick={handleConfirm}>
                            {confirmText}
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PopupNotification;

import { createContext, useContext, useEffect, useState } from "react";

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem("theme");
    return saved || "light";
  });

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
    localStorage.setItem("theme", theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === "light" ? "dark" : "light"));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};


export const useTheme = () => useContext(ThemeContext);

import { create } from 'zustand';
import authApi from '../services/auth-api';
import { jwtDecode } from 'jwt-decode';
import Cookies from 'js-cookie';

const authStore = create((set) => ({
  user: null,
  isAuthenticated: false,
  isLoading: false,
  error: null,
  typeAccount: null, // PLAYER, TEACHER, ADMIN

  setUser: (user) =>
      set((state) => {
        return {
          user,
          isAuthenticated: !!user,
          typeAccount: user?.role || null,
          error: null,
        };
      }),

  clearUser: () =>
      set({
        user: null,
        isAuthenticated: false,
        typeAccount: null,
        error: null,
      }),

  setLoading: (isLoading) => set({ isLoading }),

  setError: (error) => set({ error }),

  initialize: async () => {
    // Kiểm tra token từ Cookies trước, nếu không có thì từ sessionStorage
    let token = Cookies.get('accessToken');
    let refreshToken = Cookies.get('refreshToken');

    if (!token) {
      token = sessionStorage.getItem('accessToken');
      refreshToken = sessionStorage.getItem('refreshToken');
      // Nếu có token từ sessionStorage, đồng bộ lại vào Cookies
      if (token && refreshToken) {
        Cookies.set('accessToken', token, { expires: 7, secure: true, sameSite: 'strict' });
        Cookies.set('refreshToken', refreshToken, { expires: 7, secure: true, sameSite: 'strict' });
      }
    }

    if (!token || !refreshToken) {
      set({ user: null, isAuthenticated: false });
      return;
    }

    try {
      let decoded;
      try {
        decoded = jwtDecode(token);
      } catch (decodeError) {
        // Token không hợp lệ, clear và return
        Cookies.remove('accessToken');
        Cookies.remove('refreshToken');
        sessionStorage.removeItem('accessToken');
        sessionStorage.removeItem('refreshToken');
        set({ user: null, isAuthenticated: false });
        return;
      }

      if (decoded.exp * 1000 < Date.now()) {
        // Token hết hạn, thử refresh
        const refreshResponse = await authApi.refreshToken();
        const { accessToken: newAccessToken, refreshToken: newRefreshToken } = refreshResponse.data.data;

        // Cập nhật token mới
        Cookies.set('accessToken', newAccessToken, { expires: 7, secure: true, sameSite: 'strict' });
        Cookies.set('refreshToken', newRefreshToken, { expires: 7, secure: true, sameSite: 'strict' });
        sessionStorage.setItem('accessToken', newAccessToken);
        sessionStorage.setItem('refreshToken', newRefreshToken);

        token = newAccessToken;
      }

      // Set role from decoded token immediately
      const userWithRole = { role: decoded.typeAccount };
      set({ 
        user: userWithRole, 
        isAuthenticated: true, 
        typeAccount: decoded.typeAccount,
        isLoading: true 
      });
      
      // Then fetch full user data
      try {
        const response = await authApi.getUser();
        const fullUserWithRole = { ...response.data, role: decoded.typeAccount };
        set({ 
          user: fullUserWithRole, 
          isAuthenticated: true, 
          typeAccount: decoded.typeAccount,
          isLoading: false 
        });
      } catch (getUserError) {
        // If getUser fails, keep the basic user with role
        set({ isLoading: false });
      }
    } catch (error) {
      // Nếu refresh thất bại, clear token và chuyển về login
      Cookies.remove('accessToken');
      Cookies.remove('refreshToken');
      sessionStorage.removeItem('accessToken');
      sessionStorage.removeItem('refreshToken');
      // Chỉ set error nếu đã có token (đã từng đăng nhập)
      if (token) {
        set({ user: null, isAuthenticated: false, error: error.message, isLoading: false });
      } else {
        set({ user: null, isAuthenticated: false, isLoading: false });
      }
    }
  },

  login: async (username, password) => {
    try {
      set({ isLoading: true, error: null });
      const response = await authApi.login({ username, password });
      const { accessToken, refreshToken, ...user } = response.data.data;

      // Decode token to get typeAccount
      const decoded = jwtDecode(accessToken);
      const userWithRole = { ...user, role: decoded.typeAccount };

      // Lưu token vào Cookies và sessionStorage để persist khi reload
      Cookies.set('accessToken', accessToken, { expires: 7, secure: true, sameSite: 'strict' });
      Cookies.set('refreshToken', refreshToken, { expires: 7, secure: true, sameSite: 'strict' });
      sessionStorage.setItem('accessToken', accessToken);
      sessionStorage.setItem('refreshToken', refreshToken);

      set({ 
        user: userWithRole, 
        isAuthenticated: true, 
        typeAccount: decoded.typeAccount,
        isLoading: false 
      });
      return response;
    } catch (error) {
      set({ isLoading: false, error: error.message });
      throw error;
    }
  },

  logout: async () => {
    try {
      set({ isLoading: true, error: null });
      await authApi.logout();
      Cookies.remove('accessToken');
      Cookies.remove('refreshToken');
      sessionStorage.removeItem('accessToken');
      sessionStorage.removeItem('refreshToken');
      set({ 
        user: null, 
        isAuthenticated: false, 
        typeAccount: null,
        isLoading: false 
      });
    } catch (error) {
      set({ isLoading: false, error: error.message });
      throw error;
    }
  },
}));

export default authStore;

import { create } from 'zustand';
import socketService from '../services/socket-service';

/**
 * Game Store - Real-time game state management
 */
const useGameStore = create((set, get) => ({
    // Game state
    isGameActive: false,
    isGameStarting: false,
    isGameFinished: false,

    // Current question state
    currentQuestion: null,
    currentQuestionIndex: 0,
    totalQuestions: 0,

    // Timer state
    timeRemaining: 0,
    timerInterval: null,
    questionStartTime: null,

    // Player answers
    selectedAnswer: null,
    hasAnswered: false,
    answerResult: null,

    // Leaderboard
    players: [],
    leaderboard: [],

    // Room info
    roomId: null,
    isHost: false,

    // Loading & errors
    isLoading: false,
    error: null,

    // ==================== GAME ACTIONS ====================

    /**
     * Initialize game state for a room
     */
    initGame: (roomId, isHost = false) => {
        set({
            roomId,
            isHost,
            isGameActive: false,
            isGameStarting: false,
            isGameFinished: false,
            currentQuestion: null,
            currentQuestionIndex: 0,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            error: null
        });
    },

    /**
     * Start the game (host only)
     */
    startGame: () => {
        const { roomId, isHost } = get();

        if (!isHost) {
            set({ error: 'Only host can start the game' });
            return;
        }
        set({ isGameStarting: true, error: null });

        socketService.startGame(roomId);
    },

    /**
     * Handle game started event
     */
    onGameStarted: (data) => {
        set({
            isGameActive: true,
            isGameStarting: false,
            isGameFinished: false,
            currentQuestionIndex: 0
        });
    },

    /**
     * Load next question
     */
    loadNextQuestion: (questionData) => {
        const { currentQuestionIndex } = get();
        // Stop previous timer
        get().stopTimer();

        set({
            currentQuestion: questionData.question || questionData,
            currentQuestionIndex: currentQuestionIndex + 1,
            totalQuestions: questionData.totalQuestions || get().totalQuestions,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            questionStartTime: Date.now()
        });

        // Start timer for this question
        if (questionData.question?.timeLimit) {
            get().startTimer(questionData.question.timeLimit);
        }
    },

    /**
     * Submit answer for current question
     */
    submitAnswer: (answerId) => {
        const {
            roomId,
            currentQuestion,
            hasAnswered,
            questionStartTime
        } = get();

        if (hasAnswered) {
            return;
        }

        if (!currentQuestion) {
            return;
        }

        const timeTaken = Date.now() - questionStartTime;
        set({
            selectedAnswer: answerId,
            hasAnswered: true
        });

        socketService.submitAnswer(
            roomId,
            currentQuestion.questionId,
            answerId,
            timeTaken
        );

        // Stop timer after answer
        get().stopTimer();
    },

    /**
     * Handle answer result from server
     */
    onAnswerResult: (result) => {
        set({
            answerResult: result
        });

        // Update player score in leaderboard
        const { players } = get();
        const updatedPlayers = players.map(player => {
            if (player.userId === result.userId) {
                return {
                    ...player,
                    score: result.score,
                    totalScore: result.totalScore
                };
            }
            return player;
        });

        set({ players: updatedPlayers });
        get().updateLeaderboard();
    },

    /**
     * Request next question (host only)
     */
    nextQuestion: () => {
        const { roomId, isHost } = get();

        if (!isHost) {
            return;
        }
        socketService.nextQuestion(roomId);

        set({
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null
        });
    },

    /**
     * Handle game finished
     */
    onGameFinished: (data) => {
        get().stopTimer();

        set({
            isGameActive: false,
            isGameFinished: true,
            currentQuestion: null
        });

        get().updateLeaderboard();
    },

    /**
     * End/leave game
     */
    endGame: () => {
        get().stopTimer();

        set({
            isGameActive: false,
            isGameFinished: false,
            currentQuestion: null,
            currentQuestionIndex: 0,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            players: [],
            leaderboard: []
        });
    },

    // ==================== TIMER ACTIONS ====================

    /**
     * Start countdown timer for question
     */
    startTimer: (duration) => {
        // Clear existing timer
        get().stopTimer();

        set({ timeRemaining: duration });

        const interval = setInterval(() => {
            const { timeRemaining } = get();

            if (timeRemaining <= 0) {
                get().stopTimer();
                get().onTimerExpired();
            } else {
                set({ timeRemaining: timeRemaining - 1 });
            }
        }, 1000);

        set({ timerInterval: interval });
    },

    /**
     * Stop timer
     */
    stopTimer: () => {
        const { timerInterval } = get();

        if (timerInterval) {
            clearInterval(timerInterval);
            set({ timerInterval: null });
        }
    },

    /**
     * Handle timer expiration
     */
    onTimerExpired: () => {
        const { hasAnswered, isHost } = get();
        if (!hasAnswered) {
            // Auto-submit null answer if player didn't answer
            set({ hasAnswered: true });
        }

        // Host auto-advances to next question
        if (isHost) {
            setTimeout(() => {
                get().nextQuestion();
            }, 3000); // 3 second delay to show results
        }
    },

    // ==================== PLAYER ACTIONS ====================

    /**
     * Update players list
     */
    updatePlayers: (players) => {
        set({ players });
        get().updateLeaderboard();
    },

    /**
     * Add player to game
     */
    addPlayer: (player) => {
        const { players } = get();
        const exists = players.find(p => p.userId === player.userId);

        if (!exists) {
            set({ players: [...players, { ...player, score: 0, totalScore: 0 }] });
            get().updateLeaderboard();
        }
    },

    /**
     * Remove player from game
     */
    removePlayer: (userId) => {
        const { players } = get();
        set({
            players: players.filter(p => p.userId !== userId)
        });
        get().updateLeaderboard();
    },

    /**
     * Update leaderboard based on scores
     */
    updateLeaderboard: () => {
        const { players } = get();

        const sorted = [...players].sort((a, b) => {
            return (b.totalScore || 0) - (a.totalScore || 0);
        });

        set({ leaderboard: sorted });
    },

    // ==================== SOCKET EVENT SETUP ====================

    /**
     * Setup socket event listeners for game
     */
    setupSocketListeners: () => {
        // Game events
        socketService.onGameStarted((data) => {
            get().onGameStarted(data);
        });

        socketService.onNextQuestion((data) => {
            get().loadNextQuestion(data);
        });

        socketService.onAnswerSubmitted((result) => {
            get().onAnswerResult(result);
        });

        socketService.onGameFinished((data) => {
            get().onGameFinished(data);
        });

        // Player events
        socketService.onPlayerJoined((data) => {
            get().addPlayer(data);
        });

        socketService.onPlayerLeft((data) => {
            get().removePlayer(data.userId);
        });

        socketService.onRoomPlayers((data) => {
            get().updatePlayers(data.players);
        });

        // Error handling
        socketService.onError((error) => {
            set({ error: error.message || 'An error occurred' });
        });
    },

    /**
     * Cleanup socket listeners
     */
    cleanupSocketListeners: () => {
        // Remove all game-related listeners
        socketService.off('game-started');
        socketService.off('next-question');
        socketService.off('answer-submitted');
        socketService.off('game-finished');
        socketService.off('player-joined');
        socketService.off('player-left');
        socketService.off('room-players');
    },

    // ==================== UTILITY ====================

    /**
     * Reset game store to initial state
     */
    reset: () => {
        get().stopTimer();
        get().cleanupSocketListeners();

        set({
            isGameActive: false,
            isGameStarting: false,
            isGameFinished: false,
            currentQuestion: null,
            currentQuestionIndex: 0,
            totalQuestions: 0,
            timeRemaining: 0,
            timerInterval: null,
            questionStartTime: null,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            players: [],
            leaderboard: [],
            roomId: null,
            isHost: false,
            isLoading: false,
            error: null
        });
    },

    /**
     * Clear error
     */
    clearError: () => set({ error: null })
}));

export default useGameStore;

import socketService from '../services/socket-service';
import Cookies from 'js-cookie';

/**
 * Trình quản lý kết nối WebSocket cho Socket.IO
 *
 */
class SocketManager {
    constructor() {
        this.isInitialized = false;
        this.connectionPromise = null;
    }

    /**
     * Khởi tạo kết nối Socket.IO với quản lý token đúng cách
     * @returns {Promise<void>}
     */
    async initialize() {
        // Đã kết nối
        if (this.isInitialized && socketService.isConnected()) {
            return;
        }

        // Đang kết nối
        if (this.connectionPromise) {
            return this.connectionPromise;
        }

        this.connectionPromise = this._connect();
        return this.connectionPromise;
    }

    /**
     * Phương thức riêng tư để xử lý kết nối
     * @private
     */
    async _connect() {
        try {
            const token = this._getToken();
            if (!token) {
                throw new Error('Authentication token not found');
            }

            await socketService.connect(token);
            this.isInitialized = true;
        } catch (error) {
            this.connectionPromise = null;
            this.isInitialized = false;

            // Không ném lỗi - cho phép ứng dụng hoạt động ở chế độ REST API
            // Ứng dụng vẫn có thể hoạt động mà không có tính năng real-time
        }
    }

    /**
     * Lấy token xác thực từ bộ nhớ
     * @private
     * @returns {string|null}
     */
    _getToken() {
        // Thử cookies trước
        let token = Cookies.get('accessToken');

        // Fallback sang sessionStorage
        if (!token) {
            token = sessionStorage.getItem('accessToken');
        }

        // Fallback sang localStorage
        if (!token) {
            token = localStorage.getItem('accessToken');
        }

        return token;
    }

    /**
     * Ngắt kết nối và dọn dẹp
     */
    disconnect() {
        socketService.disconnect();
        this.isInitialized = false;
        this.connectionPromise = null;
    }

    /**
     * Kiểm tra xem có kết nối không
     * @returns {boolean}
     */
    isConnected() {
        return this.isInitialized && socketService.isConnected();
    }

    /**
     * Lấy ID người dùng hiện tại từ auth store
     * @returns {number|null}
     */
    getCurrentUserId() {
        try {
            // Import động để tránh phụ thuộc vòng tròn
            const authStore = require('../stores/auth-store').default;
            const user = authStore.getState().user;
            return user?.id;
        } catch (error) {
            return null;
        }
    }

    /**
     * Thực thi callback một lần khi socket đã kết nối
     * @param {Function} callback - Hàm cần thực thi
     * @returns {Promise<void>}
     */
    async onceConnected(callback) {
        await this.initialize();
        if (this.isConnected()) {
            callback();
        } else {
        }
    }

    /**
     * Kết nối lại với token mới
     * @returns {Promise<void>}
     */
    async reconnect() {
        this.disconnect();
        return this.initialize();
    }

    /**
     * Lấy service socket cơ bản
     * @returns {SocketService}
     */
    getService() {
        return socketService;
    }
}

// Singleton instance
const socketManager = new SocketManager();

export default socketManager;
